%[text] # 例9.2（辞書学習）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example09_02"; % mfilename

imgname = "msipimg05";
imgfmt = "tiff";

rng(0)
close all
%%
%[text] ## 画像データの読込
szOrg = [96 96];

imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),szOrg,'bilinear');

figure(1) %[output:80f7e950]
subplot(2,3,1) %[output:80f7e950]
imshow(X) %[output:80f7e950]
title('原画像') %[output:80f7e950]
%X = gpuArray(X);

%%
%[text] ### パラメータ設定
%[text] - ブロックサイズ
%[text] - 冗長度
%[text] - スパース度 \
% Block size
szBlk = [ 8 8 ];

% Redundancy ratio for RICA/K-SVD
redundancyRatio = 5/4; 

% Sparsity ratio 
sparsityRatio = 1/16;
%%
%[text] ### 中心化
%Xb = reshape(X,szBlk(1),nBlks(1),szBlk(2),nBlks(2));
%Xb = permute(Xb,[1 3 2 4]);
%Xb = reshape(Xb,szBlk(1),szBlk(2),nPatches);
[Xb,nBlks] = blockdata(X,szBlk);
%norm(Xb-reshape(im2col(X,szBlk,'distinct'),szBlk(1),szBlk(2),[]),'fro')
%nPatches = prod(nBlks);
mux = mean(Xb,2) %[output:2ddeca6b]
Xb_ = Xb - mux;
%X_ = reshape(Xb_,szBlk(1),szBlk(2),nBlks(1),nBlks(2));
%X_ = ipermute(X_,[1 3 2 4]);
%X_ = reshape(X_, size(X,1), size(X,2));
X_ = iblockdata(Xb_,szBlk,nBlks);
%%
%[text] ## 離散コサイン変換（DCT）
%[text]  $\[\\mathbf{C}\_M\]\_{k,n}=\\sqrt{\\frac{2}{M}} \\alpha\_k\\cos\\frac{k(n+1∕2)\\pi}{M},\\ k,n=0,1,\\cdots,M-1$
%[text]  $\\alpha\_k=\\left\\{\\begin{array}{ll} \\frac{1}{\\sqrt{2}} & k=0 \\\\1 & k=1,2,\\cdots,M-1\\end{array}\\right.$
%[text] #### 基底画像
%[text]  $\\mathbf{B}\_{k,\\ell}=\\mathbf{C}\_M^{-1}\\mathbf{E}\_{k,\\ell}\\mathbf{C}\_M^{-T},\\ k,\\ell=0,1,\\cdots,M-1$
%[text]  $\\mathbf{E}\_{k,\\ell}= \\mathbf{e}\_k\\mathbf{e}\_\\ell^T$
basisImagesDct = zeros(szBlk(1),szBlk(2),prod(szBlk),'like',X);
iBasis = 1;
for iRow=1:szBlk(1)
    for iCol=1:szBlk(2)
        E = zeros(szBlk,'like',X);
        E(iRow,iCol) = 1;
        basisImagesDct(:,:,iBasis) = idct2(E,szBlk(1),szBlk(2));
        iBasis = iBasis + 1;
    end
end
%[text] #### 基底画像の表示
figure(2) %[output:71f84b95]
montage(imresize(basisImagesDct,8,'nearest')+.5,'BorderSize',[2 2],... %[output:71f84b95]
    'BackgroundColor','white','ThumbnailSize',[20 20]) %[output:71f84b95]
title('Basis images of DCT') %[output:71f84b95]
drawnow
%[text] #### ブロックDCTによる合成処理とその随伴処理の定義
% ブロックDCTによる合成処理とその随伴処理の定義（GPU対応）
if isa(X_,'gpuArray')
    Cv = gpuArray(dctmtx(szBlk(1)));
    Ch = gpuArray(dctmtx(szBlk(2)));
    C = kron(Ch,Cv);
    adj_blkdct = @(x) col2im(pagefun(@mtimes,C,im2col(x,szBlk,'distinct')),szBlk,szOrg,'distinct');
    syn_blkdct = @(x) col2im(pagefun(@mtimes,C.',im2col(x,szBlk,'distinct')),szBlk,szOrg,'distinct');
else
    syn_blkdct = @(x) blockproc(x,szBlk,@(block_struct) idct2(block_struct.data));
    adj_blkdct = @(x) blockproc(x,szBlk,@(block_struct) dct2(block_struct.data));
end

%[text] 随伴関係の確認
size(X_) %[output:790e955f]
Y = adj_blkdct(X_);
V = randn(size(Y),'like',X);
U = syn_blkdct(V);
assert(abs(dot(X_(:),U(:))-dot(Y(:),V(:)))<1e-9)
%%
%[text] ## 主成分分析（PCA）
%[text] 
%[text] #### 問題設定:
%[text] `直交性と次元削減`
%[text]  $\\mathbf\\Phi\\in \\mathcal{U}(M):=\\{\\mathbf\\Phi\\in\\mathbb{K}^{M\\times M}\\mid\\mathbf\\Phi^\\textsf{H}\\mathbf\\Phi=\\mathbf\\Phi\\mathbf\\Phi^\\textsf{H}=\\mathbf{I}\_M\\}$
%[text] `を制約条件とした最小自乗問題`
%[text]  $ \\{\\hat{\\mathbf\\Phi},\\{ \\hat{{\\mathbf{y}}}\_{i} \\}\_i\\}\\in\\arg\\min\_{\\{\\mathbf\\Phi,\\{\\mathbf{y}\_{i}\\}\_i\\}}\\frac{1}{2{S}}\\sum\_{i=1}^{{S}}\\|{\\underline{\\mathbf{x}}}\_{i}-\\mathbf\\Phi\\mathbf{S}\_{\\mathcal{I}\_{k}}^\\top{\\mathbf{y}}\_{i}\\|\_2^2,\\quad\n  k\\in\\{1,2,\\ldots,M-1\\}\n \n$
%[text] `を解く．上式は等価的に`
%[text]  $  \\hat{\\mathbf\\Phi}\\in\\arg \\max \_{\\mathbf\\Phi\\in \\mathcal{U}(M)} \\mathrm{trace}\\left(\\mathbf\\Phi\_{:, 0:k-1}^\\mathtt{H} \\hat{\\mathbf\\Sigma}\_{\\mathcal{X}} \\mathbf\\Phi\_{:,0:k-1}\\right)\\\\\n\\hat{{\\mathbf{y}}}\_{i}=\\mathbf{S}\_{\\mathcal{I}\_{k}}\\hat{\\mathbf\\Phi}^\\mathtt{H}\\underline{\\mathbf{x}}\_{i},\\quad i\\in\\{1,2,\\ldots,S\\}$
%[text] `と表現できる．`ただし， $\\hat{\\mathbf\\Sigma}\_{\\mathcal{X}}:=\\textstyle S^{-1}\\sum\_{i=1}^{S}\\underline{\\mathbf{x}}\_{i}(\\underline{\\mathbf{x}}\_{i})^\\textsf{H}$は 中心窩した観測ベクトル $\\{\\underline{\\mathbf{x}}\_i\\}\_i$ （零平均を仮定）の標本分散共分散行列である．
%[text] 
%[text] #### 解:
%[text] 固有値分解
%[text]  $\\widehat{\\mathbf{\\Phi}}^\\textsf{T}{\\hat{\\mathbf\\Sigma}\_{\\mathcal{X}}}\\widehat{\\mathbf{\\Phi}}=\\mathbf{\\Lambda}\n$
%[text] ただし， $\\mathbf{\\Lambda}=\\mathrm{diag}(\\lambda\_0,\\lambda\_1,\\cdots,\\lambda\_{M-1})$． $\\lambda\_0\\geq\\lambda\_1\\geq\\cdots\\lambda\_{M-1}$ は ${\\hat{\\mathbf\\Sigma}\_{\\mathcal{X}}}$の固有値．
figure(3) %[output:763be80e]
montage(reshape(Xb(:,1:8),szBlk(1),szBlk(2),[]),'Size',[2 4]); %[output:763be80e]
drawnow

%%
%[text] 標本分散共分散行列 ${\\hat{\\mathbf\\Sigma}\_{\\mathcal{X}}}$の計算 
SigmaX = cov(Xb_.');
size(SigmaX) %[output:4646d952]
%[text] 標本分散共分散行列  ${\\hat{\\mathbf\\Sigma}\_{\\mathcal{X}}}$の固有値分解 
[Phi_pca,Lambda] = eig(SigmaX);
%[text] 固有値 $\\lambda$ の大きさの降順に列ベクトルをソート
[~,idx] = sort(diag(Lambda),'descend');
Phi_pca = Phi_pca(:,idx);
%[text] 固有ベクトルを基底画像に変換
nBases = prod(szBlk);
basisImagesPca = zeros(szBlk(1),szBlk(2),nBases,'like',X);
for iBasis = 1:nBases
    basisImagesPca(:,:,iBasis) = reshape(Phi_pca(:,iBasis),szBlk(1),szBlk(2));
end
%[text] #### 基底画像の表示（辞書）
figure(4) %[output:57e02080]
I = montage(imresize(basisImagesPca,8,'nearest')+.5,'BorderSize',[2 2],... %[output:57e02080]
    'BackgroundColor','white','ThumbnailSize',[20 20]); %[output:57e02080]
title('Basis images of PCA(KLT)') %[output:57e02080]
drawnow
%[text] #### ブロックPCAによる合成処理とその随伴処理の定義
syn_blkpca = @(x) col2im(Phi_pca*x,szBlk,szOrg,"distinct");
adj_blkpca = @(y) Phi_pca.'*im2col(y,szBlk,"distinct");
%[text] 随伴関係の確認
Y = adj_blkpca(X_);
V = randn(size(Y),'like',X);
U = syn_blkpca(V);
assert(abs(dot(X_(:),U(:))-dot(Y(:),V(:)))<1e-9)
%%
%[text] ## 再構成独立成分分析（RICA）
%[text] 
%[text] #### 問題設定:
%[text]  $  \\hat{\\mathbf\\Phi}\\in\\arg\\min\_{\\mathbf\\Phi\\in\\mathbb{K}^{M\\times P}}\\frac{1}{2{S}}\\sum\_{i=1}^{S}\\|\\underline{\\mathbf{x}}\_{i}-\\mathbf\\Phi\\mathbf\\Phi^\\textsf{H}\\underline{\\mathbf{x}}\_{i}\\|\_2^2\n  +\n  \\frac{1}{{S}}\\sum\_{i=1}^{{S}}{\\mathfrak{R}}(\\mathbf\\Phi^\\textsf{H}\\underline{\\mathbf{x}}\_{i})$
%[text] ただし，  $\\{\\mathbf{y}\_n\\}\_n\\subset\\mathbb{R}^{M}$,  $\\mathbf{\\Phi}=(\\mathbf{\\phi}\_0,\\mathbf{\\phi}\_1,\\cdots,\\mathbf{\\phi}\_{P-1\n})\\in\\mathbb{R}^{M\\times P}$, $M\\geq P$ である．
%[text] 
%[text] #### 参考文献:
%[text] Le, Quoc V., Alexandre Karpenko, Jiquan Ngiam, and Andrew Y. Ng. “ICA with Reconstruction Cost for Efficient Overcomplete Feature Learning.” Advances in Neural Information Processing Systems. Vol. 24, 2011, pp. 1017–1025. https://papers.nips.cc/paper/4467-ica-with-reconstruction-cost-for-efficient-overcomplete-feature-learning.pdf. 
%[text] 
%[text] パラメータ設定
%[text] - 繰返し回数 (Number of iterations)
%[text] - 正則化パラメータ (Regularization parameter) \
% Number of iterations
nItersRica = 2e5; 
% Regularization parameter
alpha = 1e-2;
%[text] 正則化関数の例
%[text]  ${\\mathfrak{R}}(\\mathbf\\Phi^\\top\\underline{\\mathbf{x}}):=\n\\frac{\\lambda}{2}\\sum\_{p=0}^{P-1}\\log\\circ\\cosh(2\[\\mathbf\\Phi\_{:,p}\]^\\top\\underline{\\mathbf{x}})$
figure(5) %[output:9f0f0eeb]
fplot(@(x) abs(x),[-5 5],':','LineWidth',2,'DisplayName','|\cdot|') %[output:9f0f0eeb]
hold on %[output:9f0f0eeb]
fplot(@(x) log(cosh(2*x))/2,[-5 5],'-','LineWidth',2,'DisplayName','1/2log(cosh(2\cdot))') %[output:9f0f0eeb]
xlabel('x') %[output:9f0f0eeb]
legend %[output:9f0f0eeb]
grid on %[output:9f0f0eeb]
axis equal %[output:9f0f0eeb]
hold off %[output:9f0f0eeb]
drawnow
%[text] 要素画像の数 
nDims = prod(szBlk);
nAtoms = ceil(redundancyRatio*nDims);
%[text] 辞書 $\\mathbf{\\Phi}$の初期化
%[text] - 二次元離散コサイン変換
%[text] - ランダム \
Phi_rica = randn(nDims,nAtoms,'like',X);
Phi_rica = Phi_rica/norm(Phi_rica,'fro');
for iAtom = 1:nDims
    %delta = zeros(szBlk,'like',X);
    %delta(iAtom) = 1;
    Phi_rica(:,iAtom) = reshape(basisImagesDct(:,:,iAtom),nDims,1); %reshape(idct2(delta),nDims,1);
end
%[text] 要素ベクトルを要素画像に変換 
atomicImagesRica = zeros(szBlk(1),szBlk(2),nAtoms,'like',X);
for iAtom = 1:nAtoms
    atomicImagesRica(:,:,iAtom) = reshape(Phi_rica(:,iAtom),szBlk(1),szBlk(2));
end

figure(6) %[output:4fba69aa]
montage(imresize(atomicImagesRica,8,'nearest')+.5,'BorderSize',[2 2],'Size',[ceil(nAtoms/8) 8], ... %[output:4fba69aa]
     'BackgroundColor','white','ThumbnailSize',[20 20]) %[output:4fba69aa]
title('Atomic images of initial dictionary (DCT & random)') %[output:4fba69aa]
drawnow
%[text] #### 再構成 ICA オブジェクトの作成
%[text] PCAに合わせて予め中心化したデータで学習
model = rica(Xb_.',nAtoms,...
    'IterationLimit',nItersRica,...
    'ContrastFcn','logcosh',...
    'InitialTransformWeight',Phi_rica,...
    'Lambda',1/(2*alpha));
%[text] コスト評価のグラフ 
info = model.FitInfo;
figure(7) %[output:9ed2b788]
plot(info.Iteration,info.Objective) %[output:9ed2b788]
xlabel('Number of iteration') %[output:9ed2b788]
ylabel('Cost') %[output:9ed2b788]
grid on %[output:9ed2b788]
drawnow
%[text] 要素ベクトルを要素画像に変換
Phi_rica = model.TransformWeights;
atomicImagesRica = zeros(szBlk(1),szBlk(2),nAtoms,'like',X);
for iAtom = 1:nAtoms
    atomicImagesRica(:,:,iAtom) = reshape(Phi_rica(:,iAtom),szBlk(1),szBlk(2));
end
%[text] #### 要素画像の表示（辞書）
figure(8) %[output:3450bd22]
montage(imresize(atomicImagesRica,8,'nearest')+.5,'BorderSize',[2 2],'Size',[ceil(nAtoms/8) 8], ... %[output:3450bd22]
     'BackgroundColor','white','ThumbnailSize',[20 20]) %[output:3450bd22]
title('Atomic images of RICA') %[output:3450bd22]
drawnow
%[text] #### ブロックRICAによる合成処理とその随伴処理の定義
syn_blkrica = @(x) col2im(Phi_rica*x,szBlk,szOrg,"distinct");
adj_blkrica = @(y) Phi_rica.'*im2col(y,szBlk,"distinct");
%[text] 随伴関係の確認
Y = adj_blkrica(X_);
V = randn(size(Y),'like',X);
U = syn_blkrica(V);
assert(abs(dot(X_(:),U(:))-dot(Y(:),V(:)))<1e-9)
%%
%[text] ## K-特異値分解
%[text] パラメータ設定
%[text] - 繰返し回数 (Number of iterations) \
% Number of iterations
nItersKsvd = 1e5;
%[text] #### 問題設定 (Problem setting):
%[text]  $  \\{\\hat{\\mathbf\\Phi},\\{\\hat{\\mathbf{y}}\_{i}\\}\\}\\in\\arg\\min\_{\\mathbf\\Phi,\\{\\mathbf{y}\_{i}\\}}\\frac{1}{2{S}}\\sum\_{i=1}^{S}\\|\\underline{\\mathbf{x}}\_{i}-\\mathbf\\Phi\\mathbf{y}\_{i}\\|\_2^2,\\quad \\text{s.t.} \\quad \\|\\mathbf{y}\_{i}\\|\_0\\leq {K} \\ll M$
%[text] #### アルゴリズム :
%[text] スパース近似ステップと辞書更新ステップを繰返す．
%[text] - スパース近似ステップ  \
%[text]  $      \\hat{\\mathbf{y}}\_{i} \\in\\arg\\min\_{\\mathbf{y}\\in\\mathbb{K}^P}\\frac12\\|\n        \\underline{\\mathbf{x}}\_{i}-\\hat{\\mathbf\\Phi}{\\mathbf{y}}\\|\_2^2,\\quad \\mathrm{s.t.}\\quad \\|\\mathbf{y}\\|\_0\\leq {K}\n      \\\\\n      \\mathcal{P}\_i =\\{p\\in\\{0,1,\\ldots,P-1\\}\\mid \[\\hat{\\mathbf{y}}\_i\]\_p\\neq 0\\}$
%[text] - 辞書更新ステップ  \
%[text]  $\\hat{\\mathbf\\Phi}\\in\\arg\\min\_{\\mathbf\\Phi\\in\\mathbb{K}^{M\\times P},\\{\\mathbf{y}\_i\\}\\subset\\mathbb{K}^{P}}\\frac{1}{2{S}}\\sum\_{i=1}^{{S}}\\|\\underline{\\mathbf{x}}\_{i}-\\mathbf\\Phi(\\mathbf\\zeta\_{\\mathcal{P}\_i}\\odot{\\mathbf{y}\_i})\\|\_2^2\\\\\n      =\\arg\\min\_{\\mathbf\\Phi\\in\\mathbb{K}^{M\\times P},\\mathbf{Y}\\in\\mathbb{K}^{P\\times S}\n      }\\frac{1}{2{S}}\\|\\mathbf{X}-\\mathbf\\Phi(\\mathbf{Z}\\odot{\\mathbf{Y}})\\|\_\\mathrm{F}^2 \\\\\n      =\\arg\\min\_{\\mathbf\\Phi,\\mathbf{Y}}\\frac{1}{2{S}}\\|(\\mathbf{X}-\\mathbf\\Phi\_{:,\\backslash p}{(\\mathbf{Z}\\odot\\mathbf{Y})}\_{\\backslash p,:})-\\mathbf\\Phi\_{:,p}{(\\mathbf{Z}\\odot\\mathbf{Y})}\_{p,:}\\|\_\\mathrm{F}^2$
%[text] 
%[text] 係数の数 
nCoefsKsvd = max(floor(sparsityRatio*nDims),1);
%[text] 辞書 $\\mathbf{\\Phi}$の初期化 
%[text] - 二変量離散コサイン変換
%[text] - ランダム  \
Phi_ksvd = randn(nDims,nAtoms,'like',X);
Phi_ksvd = Phi_ksvd/norm(Phi_ksvd,'fro');
for iAtom = 1:nDims
    %delta = zeros(szBlk,'like',X);
    %delta(iAtom) = 1;
    Phi_ksvd(:,iAtom) = reshape(basisImagesDct(:,:,iAtom),nDims,1); %reshape(idct2(delta),nDims,1);
end
%[text] 要素ベクトルを要素画像に変換
atomicImagesKsvd = zeros(szBlk(1),szBlk(2),nAtoms,'like',X);
for iAtom = 1:nAtoms
    atomicImagesKsvd(:,:,iAtom) = reshape(Phi_ksvd(:,iAtom),szBlk(1),szBlk(2));
end
figure(9)
montage(imresize(atomicImagesKsvd,8,'nearest')+.5,'BorderSize',[2 2],'Size',[ceil(nAtoms/8) 8], ... %[output:99297214]
     'BackgroundColor','white','ThumbnailSize',[20 20]) %[output:99297214]
title('Atomic images of initial dictionary (DCT & random)') %[output:99297214]
drawnow
%[text] #### スパース近似ステップと辞書更新ステップの繰り返し
%[text] - スパース近似： 直交マッチング追跡 (OMP)
%[text] - 辞書更新： 特異値分解(SVD)と1-ランク近似  \
%[text] 辞書更新の内容
%[text] 1. $p\\leftarrow 0$
%[text] 2. 誤差行列 $\\mathbf{E}\_p$ を定義：$\\mathbf{E}\_p\\colon:=\\mathbf{X}-\\mathbf\\Phi\_{:,\\backslash p}{(\\mathbf{Z}\\odot\\mathbf{Y})}\_{\\backslash p,:}\\in\\mathbb{K}^{P\\times S}$
%[text] 3. データ行 $\\hat{\\mathbf{Y}}\_{p,\\colon}$の非零値を抽出する行列 $\\mathbf{S}\_{\\mathcal{J}\_p}$を定義： $\\hat{\\mathbf{Y}}\_{p,:}^\\mathrm{R}\\mathbf{S}\_{\\mathcal{J}\_p}=\\hat{\\mathbf{Y}}\_{p,:}\n\\Leftrightarrow\n\\hat{\\mathbf{Y}}\_{p,:}^\\mathrm{R}=\\hat{\\mathbf{Y}}\_{p,:}\\mathbf{S}\_{\\mathcal{J}\_p}^\\top$
%[text] 4. 誤差行列 $\\mathbf{E}\_p$ を行列 $\\mathbf{S}\_{\\mathcal{J}\_p}$で縮退： $\\mathbf{E}\_p^\\mathrm{R}:=\\mathbf{E}\_p\\mathbf{S}\_{\\mathcal{J}\_p}^\\top\n \\in\\mathbb{K}^{M\\times |\\mathcal{J}\_p|}$
%[text] 5. 縮退した誤差行列$\\mathbf{E}\_k^R$を特異値分解：$\\mathbf{E}\_k^R =\\mathbf{U}\\mathbf{S}\\mathbf{V}^T\n=\\left(\\mathbf{u}\_0,\\mathbf{u}\_1,\\cdots,\\mathbf{u}\_{r-1}\\right)\\mathrm{diag}(\\sigma\_0,\\sigma\_1,\\cdots,\\sigma\_{r-1})\\left(\\mathbf{v}\_0,\\mathbf{v}\_1,\\cdots,\\mathbf{v}\_{r-1}\\right)^T$
%[text] 6. 要素ベクトル $\\mathbf{\\phi}\_p$ を更新： $\\mathbf{\\phi}\_p\\leftarrow \\mathbf{u}\_p$
%[text] 7. データ行$\\hat{\\mathbf{Y}}\_{p,\\colon}$を更新： $\\hat{\\mathbf{Y}}\_{p,\\colon}\\leftarrow \\sigma\_0\\mathbf{v}\_{0}^T$
%[text] 8. $p\\leftarrow p+1$
%[text] 9. $p\\leq N$ ならば 2. へ $p\>N$ ならば終了 \
%[text] ただし， $\\sigma\_0$ を最大特異値とする．
%[text] #### 交互ステップの繰返し計算
%[text] PCAに合わせて予め中心化したデータで学習
cost = zeros(1,nItersKsvd,'like',X);
nSamples = size(Xb_,2);
for iIter = 1:nItersKsvd %[output:group:4907f660]
    Y = zeros(nAtoms,nSamples,'like',X);
    % Sparse approximation
    parfor iSample = 1:nSamples %[output:34380fa7]
        %x_ = reshape(Xb_(:,:,iSample),nDims,[]);
        y = omp(Xb_(:,iSample),Phi_ksvd,nCoefsKsvd);
        Y(:,iSample) = y;
    end
    % Dictionary update
    for iAtom = 1:nAtoms
        idxset = setdiff(1:nAtoms,iAtom);
        yp = Y(iAtom,:);
        suppp = find(yp);
        %
        Epred = Xb_(:,suppp)-Phi_ksvd(:,idxset)*Y(idxset,suppp);
        %
        if ~isempty(suppp)
            [U,S,V] = svd(Epred,'econ');
            ap = U(:,1);
            ypred = S(1,1)*V(:,1)';
            %
            Phi_ksvd(:,iAtom) = ap;
            Y(iAtom,suppp) = ypred;
        end
    end
    cost(iIter) = (norm(Xb_-Phi_ksvd*Y,'fro')^2)/(2*nSamples);
end %[output:group:4907f660]
%[text] コスト評価のグラフ 
figure(10)
plot(cost) %[output:4e17f9f3]
xlabel('Number of iteration') %[output:4e17f9f3]
ylabel('Cost') %[output:4e17f9f3]
grid on %[output:4e17f9f3]
drawnow
%[text] 要素ベクトルを要素画像に変換 
atomicImagesKsvd = zeros(szBlk(1),szBlk(2),nAtoms,'like',X);
for iAtom = 1:nAtoms
    atomicImagesKsvd(:,:,iAtom) = reshape(Phi_ksvd(:,iAtom),szBlk(1),szBlk(2));
end
figure(11)
montage(imresize(atomicImagesKsvd,8,'nearest')+.5,'BorderSize',[2 2],'Size',[ceil(nAtoms/8) 8],... %[output:7c3e71f4]
    'BackgroundColor','white','ThumbnailSize',[20 20]) %[output:7c3e71f4]
title('Atomic images of K-SVD') %[output:7c3e71f4]
drawnow
%[text] #### ブロックK-特異値分解による合成処理とその随伴処理の定義
syn_blkksvd = @(x) col2im(Phi_ksvd*x,szBlk,szOrg,"distinct");
adj_blkksvd = @(y) Phi_ksvd.'*im2col(y,szBlk,"distinct");
%[text] 随伴関係の確認
Y = adj_blkksvd(X_);
V = randn(size(Y),'like',X);
U = syn_blkksvd(V);
assert(abs(dot(X_(:),U(:))-dot(Y(:),V(:)))<1e-9)
%%
%[text] #### 直交マッチング追跡関数の定義
function x = omp(y,Phi,nCoefs)
% Initialization
nDims = size(Phi,1);
nAtoms = size(Phi,2);
e = ones(nAtoms,1,'like',y);
a = zeros(nAtoms,1,'like',y);
g = zeros(nAtoms,1,'like',y);
x = zeros(nAtoms,1,'like',y);
v = zeros(nDims,1,'like',y);
r = y - v;
supp = [];
k = 0;
while k < nCoefs
    % Matching process
    rr = r.'*r;
    for m = setdiff(1:nAtoms,supp)
        d = Phi(:,m);
        g(m) = d.'*r; % γm=<dm,r>
        a(m) = g(m)/(d.'*d); % Normalize αm=γm/||dm||^2
        e(m) = rr - g(m)*a(m); % <r-dm/||dm||^2,r>
    end
    % Minimum value search (pursuit)
    [~,mmin]= min(e);
    % Update the support
    supp = union(supp,mmin);
    subPhi = Phi(:,supp);
    %x(supp) = pinv(subPhi) * y;
    x(supp) = subPhi\y;
    % Synthesis process
    v = Phi*x;
    % Residual
    r = y - v;
    % Update
    k = k + 1;
end
end

function [Xb,nBlks] = blockdata(X,szBlk)
nRows = size(X,1)/szBlk(1);
nCols = size(X,2)/szBlk(2);
%nPatches = nRows*nCols;
%Xb = reshape(X,szBlk(1),nRows,szBlk(2),nCols);
%Xb = permute(Xb,[1 3 2 4]);
%Xb = reshape(Xb,szBlk(1),szBlk(2),nPatches);
Xb = im2col(X,szBlk,'distinct');
nBlks = [nRows nCols];
end

function X = iblockdata(Xb,szBlk,nBlks)
%nRows = nBlks(1);
%nCols = nBlks(2);
%X = reshape(Xb,szBlk(1),szBlk(2),nRows,nCols);
%X = ipermute(X,[1 3 2 4]);
%X = reshape(X, szBlk(1)*nRows, szBlk(2)*nCols);
X = col2im(Xb,szBlk,szBlk.*nBlks,'distinct');
end

